 9→import jakarta.servlet.http.HttpServletRequest;
10→import jakarta.validation.Valid;
11→import lombok.RequiredArgsConstructor;
12→import lombok.extern.slf4j.Slf4j;
13→import org.springframework.security.core.Authentication;
14→import org.springframework.web.bind.annotation.*;
15→
16→/**
17→ * 开放 API — AI 通过 API Token 调用
18→ */
19→@Slf4j
20→@RestController
21→@RequestMapping("/api/open")
22→@RequiredArgsConstructor
23→public class OpenApiController {
24→
25→    private final QuestionService questionService;
26→    private final ApiTokenService apiTokenService;
27→    private final ObjectMapper objectMapper;
28→
29→    /**
30→     * 批量新增题目（复用已有逻辑）
31→     */
32→    @PostMapping("/exams/{examId}/questions/batch")
33→    public Result<Integer> batchCreate(@PathVariable Long examId,
34→                                       @Valid @RequestBody QuestionBatchRequest req,
35→                                       Authentication auth,
36→                                       HttpServletRequest httpRequest) {
37→        long startTime = System.currentTimeMillis();
38→        // credentials 中存放了 tokenId（在 Filter 中设置）
39→        Long tokenId = (Long) auth.getCredentials();
40→        int count = req.getQuestions() != null ? req.getQuestions().size() : 0;
41→        log.info("[lbl][OpenAPI][BATCH_CREATE] 批量导入题目请求, examId={}, count={}, tokenId={}",
42→                examId, count, tokenId);
43→
44→        Result<Integer> result;
45→        int responseCode = 0;
46→        String responseBody = null;
47→        try {
48→            int created = questionService.batchCreate(examId, req);
49→            result = Result.ok(created);
50→            responseCode = 200;
51→            responseBody = String.valueOf(created);
52→        } catch (Exception e) {
53→            responseCode = 500;
54→            responseBody = e.getMessage();
55→            throw e;
56→        } finally {
57→            // 记录调用日志
58→            long duration = System.currentTimeMillis() - startTime;
59→            try {
60→                String reqBodySummary = count + " questions for exam " + examId;
61→                apiTokenService.logCall(ApiCallLog.builder()
62→                        .tokenId(tokenId)
63→                        .requestPath(httpRequest.getRequestURI())
64→                        .requestMethod(httpRequest.getMethod())
65→                        .requestBody(reqBodySummary)
66→                        .responseCode(responseCode)
67→                        .responseBody(responseBody)
68→                        .durationMs((int) duration)
69→                        .clientIp(getClientIp(httpRequest))
70→                        .build());
71→            } catch (Exception logEx) {
72→                log.warn("[lbl][OpenAPI][LOG] 记录调用日志失败, tokenId={}, error={}", tokenId, logEx.getMessage());
73→            }
74→        }
75→        return result;
76→    }
77→
78→    private String getClientIp(HttpServletRequest request) {
79→        String ip = request.getHeader("X-Forwarded-For");
80→        if (ip != null && !ip.isEmpty() && !"unknown".equalsIgnoreCase(ip)) {
81→            return ip.split(",")[0].trim();
82→        }
83→        ip = request.getHeader("X-Real-IP");
84→        if (ip != null && !ip.isEmpty() && !"unknown".equalsIgnoreCase(ip)) {
85→            return ip;
86→        }
87→        return request.getRemoteAddr();
88→    }
89→}
